import{c as t,Q as n,j as r,m as e}from"./chunks/framework.DpF7k2f3.js";const _=JSON.parse('{"title":"제9장 LangChain 실전","description":"","frontmatter":{"outline":"deep"},"headers":[],"relativePath":"ko/part3-practice/chapter9.md","filePath":"ko/part3-practice/chapter9.md"}'),p={name:"ko/part3-practice/chapter9.md"};function i(o,a,l,c,h,s){return n(),r("div",null,[...a[0]||(a[0]=[e('<h1 id="제9장-langchain-실전" tabindex="-1">제9장 LangChain 실전 <a class="header-anchor" href="#제9장-langchain-실전" aria-label="Permalink to &quot;제9장 LangChain 실전&quot;">​</a></h1><p>##本章에서 배울 것들</p><p>여러분, 실전 시간입니다!</p><p>앞에서 탄탄한 기반을 다졌습니다 - 대규모 모델 호출 가능(제5장), AI에 지식库 연결 방법 이해(제6장), 에이전트가 어떻게 작동하는지 파악(제7장). 이제 이러한 능력을 <strong>진짜 쓸 수 있는 것으로 연결</strong>할 때입니다.</p><p>이 챕터에서는 LangChain을 다룹니다 - 현재 가장 인기 있는 AI 앱 개발 프레임워크.</p><p>솔직히 말씀드리겠습니다: <strong>LangChain은 진입이 쉽지만 마스터하기 어렵습니다.</strong> 공식 튜토리얼은 모두 Hello World 수준이고, 실제 프로덕션 환경에서는各种问题接踵而至: 버전 비호환, 디버깅 어려움, 성능落后 등...</p><p>하지만! LangChain은 여전히 현재 가장 주류인 AI 앱 개발 프레임워크이고, 이를 배우면 취업에 가산점이 되고 프로젝트 효율이 2배로 늘어납니다. 그리고 2025-2026년에 LangChain은 <strong>LangGraph</strong>를 출시했는데, 이것은 복잡한 에이전트 오케스트레이션을 선언적 프로그래밍으로 바꿔버렸습니다 - 어셈블리에서 Python으로進化したような爽快感.</p><p>그래서 이 챕터에서:</p><ul><li>LangChain 아키텍처와 코어 모듈 빠른 훑어보기</li><li>LCEL 심층 분석 - LangChain의 정수, 반드시 깊이 이해해야 함</li><li><strong>하이라이트: LangGraph</strong> - 2026년 에이전트 개발 표준 도구</li><li>RAG 구현을 토이에서 프로덕션급으로 업그레이드</li><li>멀티 도구 에이전트 심층 분석</li></ul><hr><blockquote><p><strong>전체 번역은 곧 제공될 예정입니다. 지금은中文版을 읽으실 수 있습니다.</strong></p><p>中文原文：<a href="/jumpstart-ai/zh/part3-practice/chapter9.html">中文版阅读</a></p></blockquote>',11)])])}const d=t(p,[["render",i]]);export{_ as __pageData,d as default};
